import{_ as a,o as i,c as l,al as r}from"./chunks/framework.BOATtE-F.js";const u=JSON.parse('{"title":"预览与分享","description":"","frontmatter":{"prev":{"text":"配置参考","link":"/posts/docs/ageratum/09-config"}},"headers":[],"relativePath":"posts/docs/ageratum/10-preview-and-sharing.md","filePath":"posts/docs/ageratum/10-preview-and-sharing.md","lastUpdated":1774974346000}'),d={name:"posts/docs/ageratum/10-preview-and-sharing.md"};function o(t,e,s,n,h,c){return i(),l("div",null,[...e[0]||(e[0]=[r(`<h1 id="预览与分享" tabindex="-1">预览与分享 <a class="header-anchor" href="#预览与分享" aria-label="Permalink to “预览与分享”">​</a></h1><p>本文档聚焦 Ageratum 的两条协作链路：<strong>本地预览</strong>（快速迭代文档）与<strong>多人分享</strong>（把当前文档发送给其他玩家）。</p><hr><h2 id="_1-本地预览模式" tabindex="-1">1. 本地预览模式 <a class="header-anchor" href="#_1-本地预览模式" aria-label="Permalink to “1. 本地预览模式”">​</a></h2><p>预览模式用于在不重启游戏、不重载资源包的情况下，实时查看本地 Markdown 修改效果。</p><h3 id="启用条件" tabindex="-1">启用条件 <a class="header-anchor" href="#启用条件" aria-label="Permalink to “启用条件”">​</a></h3><p>在 <code>ageratum-client.toml</code> 中开启：</p><div class="language-toml line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">enablePreview = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">previewPath = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ageratum_preview&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="命令入口" tabindex="-1">命令入口 <a class="header-anchor" href="#命令入口" aria-label="Permalink to “命令入口”">​</a></h3><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>/ageratum preview</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>该命令会尝试打开：</p><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&lt;minecraft_dir&gt;/&lt;previewPath&gt;/index.md</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>默认路径即：<code>&lt;minecraft_dir&gt;/ageratum_preview/index.md</code>。</p><h3 id="刷新机制" tabindex="-1">刷新机制 <a class="header-anchor" href="#刷新机制" aria-label="Permalink to “刷新机制”">​</a></h3><ul><li>预览文档在界面打开后会周期检查文件变化（修改时间 + 文件大小）。</li><li>检查间隔为约 <code>500ms</code>。</li><li>检测到变化后会重新解析 Markdown，并尽量保留当前阅读位置（滚动位置与侧栏状态）。</li></ul><h3 id="预览文档路径规则" tabindex="-1">预览文档路径规则 <a class="header-anchor" href="#预览文档路径规则" aria-label="Permalink to “预览文档路径规则”">​</a></h3><ul><li>预览命名空间固定为 <code>ageratum_review</code>（内部使用）。</li><li>文件参数会做规范化： <ul><li>空值变为 <code>index</code></li><li><code>\\\\</code> 转 <code>/</code></li><li>去掉前导 <code>/</code></li><li>去掉 <code>.md</code> 后缀后再统一补回</li><li><code>.</code> 会被忽略，<code>..</code> 会回退一级目录</li><li>路径分段会转成小写</li></ul></li></ul><p>这保证了 <code>/ageratum preview</code> 与内部跳转在不同平台上一致。</p><hr><h2 id="_2-文档分享机制" tabindex="-1">2. 文档分享机制 <a class="header-anchor" href="#_2-文档分享机制" aria-label="Permalink to “2. 文档分享机制”">​</a></h2><p>Ageratum 提供一个“分享当前文档”的网络流程，目标是让玩家之间快速同步阅读页。</p><h3 id="网络载荷" tabindex="-1">网络载荷 <a class="header-anchor" href="#网络载荷" aria-label="Permalink to “网络载荷”">​</a></h3><h4 id="openguidepayload-服务端-客户端" tabindex="-1"><code>OpenGuidePayload</code>（服务端 -&gt; 客户端） <a class="header-anchor" href="#openguidepayload-服务端-客户端" aria-label="Permalink to “OpenGuidePayload（服务端 -&gt; 客户端）”">​</a></h4><ul><li>字段：<code>location: ResourceLocation</code></li><li>用途：通知目标客户端打开指定文档</li></ul><h4 id="shareguidepayload-客户端-服务端" tabindex="-1"><code>ShareGuidePayload</code>（客户端 -&gt; 服务端） <a class="header-anchor" href="#shareguidepayload-客户端-服务端" aria-label="Permalink to “ShareGuidePayload（客户端 -&gt; 服务端）”">​</a></h4><ul><li>字段： <ul><li><code>location: ResourceLocation</code></li><li><code>anchor: String</code></li><li><code>sameTeam: boolean</code></li></ul></li><li>用途：请求服务端向其他玩家发送“可点击的文档消息”</li></ul><h3 id="服务端处理逻辑" tabindex="-1">服务端处理逻辑 <a class="header-anchor" href="#服务端处理逻辑" aria-label="Permalink to “服务端处理逻辑”">​</a></h3><p><code>ServerPayloadHandler.handleShareGuide</code> 会：</p><ol><li>获取发起玩家与玩家列表。</li><li>根据 <code>sameTeam</code> 决定是否过滤到同队成员。</li><li>构造系统消息（含可点击按钮）。</li><li>目标玩家点击后执行 <code>/ageratum &quot;namespace&quot; &quot;path&quot; [anchor]</code>。</li></ol><h3 id="队伍内分享配置" tabindex="-1">队伍内分享配置 <a class="header-anchor" href="#队伍内分享配置" aria-label="Permalink to “队伍内分享配置”">​</a></h3><p><code>ageratum-client.toml</code> 的 <code>shareGuideOnlyInTeam</code> 会影响分享时的 <code>sameTeam</code> 参数。若你希望多人服默认更克制，建议开启。</p><hr><h2 id="_3-与语言回退的关系" tabindex="-1">3. 与语言回退的关系 <a class="header-anchor" href="#_3-与语言回退的关系" aria-label="Permalink to “3. 与语言回退的关系”">​</a></h2><p>无论是普通打开还是分享跳转，文档定位都遵循同一规则：</p><ol><li>先尝试客户端当前语言目录（如 <code>zh_cn</code>）。</li><li>未命中时回退到 <code>en_us</code>。</li></ol><p>这意味着分享链接通常只需要传递同一个 <code>ResourceLocation</code> 路径，不需要为每个语言单独维护命令。</p><hr><h2 id="_4-推荐协作流程" tabindex="-1">4. 推荐协作流程 <a class="header-anchor" href="#_4-推荐协作流程" aria-label="Permalink to “4. 推荐协作流程”">​</a></h2><h3 id="单人写作" tabindex="-1">单人写作 <a class="header-anchor" href="#单人写作" aria-label="Permalink to “单人写作”">​</a></h3><ol><li>开启 <code>enablePreview</code>。</li><li>在 <code>previewPath</code> 下编辑文档。</li><li>游戏内打开 <code>/ageratum preview</code> 实时校对。</li><li>定稿后再拷贝到模组资源目录（<code>assets/&lt;modid&gt;/ageratum/&lt;lang&gt;/...</code>）。</li></ol><h3 id="多人联机校审" tabindex="-1">多人联机校审 <a class="header-anchor" href="#多人联机校审" aria-label="Permalink to “多人联机校审”">​</a></h3><ol><li>文档作者在本地调好页面。</li><li>通过分享功能将目标页发送给测试玩家。</li><li>测试玩家点消息按钮直接跳转同一页。</li><li>收集反馈后继续预览迭代。</li></ol><hr><h2 id="_5-常见问题" tabindex="-1">5. 常见问题 <a class="header-anchor" href="#_5-常见问题" aria-label="Permalink to “5. 常见问题”">​</a></h2><h3 id="q1-输入-ageratum-preview-没反应" tabindex="-1">Q1: 输入 <code>/ageratum preview</code> 没反应？ <a class="header-anchor" href="#q1-输入-ageratum-preview-没反应" aria-label="Permalink to “Q1: 输入 /ageratum preview 没反应？”">​</a></h3><p>优先检查：</p><ul><li><code>enablePreview</code> 是否为 <code>true</code></li><li><code>&lt;minecraft_dir&gt;/&lt;previewPath&gt;/index.md</code> 是否存在</li><li>文件是否 UTF-8 编码</li></ul><h3 id="q2-修改了文件但界面不刷新" tabindex="-1">Q2: 修改了文件但界面不刷新？ <a class="header-anchor" href="#q2-修改了文件但界面不刷新" aria-label="Permalink to “Q2: 修改了文件但界面不刷新？”">​</a></h3><ul><li>等待约半秒到一秒（轮询刷新）</li><li>确认编辑器真实写入了文件（非仅缓存）</li><li>确认路径位于 <code>previewPath</code> 下</li></ul><h3 id="q3-分享后别人打不开页面" tabindex="-1">Q3: 分享后别人打不开页面？ <a class="header-anchor" href="#q3-分享后别人打不开页面" aria-label="Permalink to “Q3: 分享后别人打不开页面？”">​</a></h3><ul><li>检查对方是否安装了相同资源内容</li><li>检查目标页面在对方语言目录是否存在（或可回退到 <code>en_us</code>）</li><li>若启用了队伍限制，确认双方队伍一致</li></ul><hr><h2 id="参见" tabindex="-1">参见 <a class="header-anchor" href="#参见" aria-label="Permalink to “参见”">​</a></h2><ul><li><a href="./09-config.html">配置参考</a></li><li><a href="./01-getting-started.html">快速入门</a></li><li><a href="./07-api-reference.html">API 参考</a></li></ul>`,54)])])}const m=a(d,[["render",o]]);export{u as __pageData,m as default};
